-- Kategori Doa Mustajab — waktu, keadaan, dan doa yang dijanjikan ijabah,
-- seluruhnya bersumber hadits sahih/hasan dengan nomor riwayat.
-- Idempoten: INSERT OR IGNORE + UNIQUE(category_slug, item_order).
INSERT OR IGNORE INTO amalan_category (slug, grp, name_id, name_ar, icon, sort_order) VALUES ('doa-mustajab', 'doa', 'Doa Mustajab — Waktu & Keadaan Terkabulnya Doa', 'أوقات إجابة الدعاء', '🕰️', 16);
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 1, 'Sepertiga Malam Terakhir', 'يَنْزِلُ رَبُّنَا تَبَارَكَ وَتَعَالَى كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا حِينَ يَبْقَى ثُلُثُ اللَّيْلِ الآخِرُ يَقُولُ: مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ، مَنْ يَسْأَلُنِي فَأُعْطِيَهُ، مَنْ يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ', 'Yanzilu Rabbuna tabaraka wa ta''ala kulla lailatin ilas-sama''id-dunya hina yabqa tsulutsul-lailil-akhir, yaqulu: man yad''uni fa astajiba lahu, man yas''aluni fa u''thiyahu, man yastaghfiruni fa aghfira lahu', 'Tuhan kita turun setiap malam ke langit dunia ketika tersisa sepertiga malam terakhir, lalu berfirman: "Siapa yang berdoa kepada-Ku akan Aku kabulkan, siapa yang meminta kepada-Ku akan Aku beri, siapa yang memohon ampun kepada-Ku akan Aku ampuni."', 'Inilah waktu doa paling utama dalam sehari-semalam. Bangunlah sebelum subuh walau sebentar: shalat tahajud, beristighfar, lalu sampaikan hajat Anda.', NULL, 'HR. Bukhari no. 1145, Muslim no. 758');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 2, 'Antara Adzan dan Iqamah', 'الدُّعَاءُ لَا يُرَدُّ بَيْنَ الأَذَانِ وَالإِقَامَةِ', 'Ad-du''a''u la yuraddu bainal-adzani wal-iqamah', 'Doa di antara adzan dan iqamah tidak ditolak.', 'Jeda pendek menjelang shalat berjamaah adalah pintu ijabah yang sering terlewat. Isi dengan doa, bukan obrolan.', NULL, 'HR. Abu Dawud no. 521, Tirmidzi no. 212 (sahih)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 3, 'Saat Sujud', 'أَقْرَبُ مَا يَكُونُ الْعَبْدُ مِنْ رَبِّهِ وَهُوَ سَاجِدٌ، فَأَكْثِرُوا الدُّعَاءَ', 'Aqrabu ma yakunul-''abdu min rabbihi wa huwa sajidun, fa aktsirud-du''a', 'Keadaan seorang hamba yang paling dekat dengan Tuhannya adalah ketika ia sujud, maka perbanyaklah doa (di dalamnya).', 'Dalam sujud — terutama di shalat sunnah — panjatkan hajat dengan bahasa apa pun yang Anda pahami setelah bacaan sujud.', NULL, 'HR. Muslim no. 482');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 4, 'Setelah Shalat Fardhu', 'قِيلَ: يَا رَسُولَ اللهِ أَيُّ الدُّعَاءِ أَسْمَعُ؟ قَالَ: جَوْفَ اللَّيْلِ الآخِرِ وَدُبُرَ الصَّلَوَاتِ الْمَكْتُوبَاتِ', 'Qila: ya Rasulallah, ayyud-du''a''i asma''? Qala: jaufal-lailil-akhiri wa duburash-shalawatil-maktubat', 'Ditanyakan: "Wahai Rasulullah, doa manakah yang paling didengar?" Beliau menjawab: "Doa di tengah malam terakhir dan setelah shalat-shalat wajib."', 'Jangan buru-buru beranjak setelah salam: dzikir, lalu berdoa.', NULL, 'HR. Tirmidzi no. 3499 (hasan)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 5, 'Sa''atul Ijabah di Hari Jumat', 'فِيهِ سَاعَةٌ لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ وَهُوَ قَائِمٌ يُصَلِّي يَسْأَلُ اللهَ شَيْئًا إِلَّا أَعْطَاهُ إِيَّاهُ', 'Fihi sa''atun la yuwafiquha ''abdun muslimun wa huwa qa''imun yushalli yas''alullaha syai''an illa a''thahu iyyah', 'Pada hari Jumat ada satu waktu yang tidaklah seorang hamba muslim mendapatinya sedang ia berdiri shalat memohon sesuatu kepada Allah, melainkan Allah memberikannya.', 'Pendapat terkuat: setelah ashar hingga maghrib di hari Jumat, atau antara duduknya imam hingga selesai shalat. Perbanyak doa di kedua rentang itu.', NULL, 'HR. Bukhari no. 935, Muslim no. 852');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 6, 'Saat Berbuka bagi Orang yang Berpuasa', 'إِنَّ لِلصَّائِمِ عِنْدَ فِطْرِهِ لَدَعْوَةً مَا تُرَدُّ', 'Inna lish-sha''imi ''inda fithrihi lada''watan ma turadd', 'Sesungguhnya orang yang berpuasa memiliki doa yang tidak ditolak ketika ia berbuka.', 'Sebelum atau saat berbuka, sisihkan waktu sejenak untuk doa pribadi — jangan habiskan detik-detik mustajab itu hanya untuk menyiapkan hidangan.', NULL, 'HR. Ibnu Majah no. 1753 (hasan)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 7, 'Tiga Doa yang Pasti Dikabulkan', 'ثَلَاثُ دَعَوَاتٍ مُسْتَجَابَاتٌ لَا شَكَّ فِيهِنَّ: دَعْوَةُ الْمَظْلُومِ، وَدَعْوَةُ الْمُسَافِرِ، وَدَعْوَةُ الْوَالِدِ عَلَى وَلَدِهِ', 'Tsalatsu da''awatin mustajabatun la syakka fihinna: da''watul-mazhlum, wa da''watul-musafir, wa da''watul-walidi ''ala waladih', 'Tiga doa yang mustajab tanpa diragukan: doa orang yang terzalimi, doa musafir, dan doa orang tua untuk anaknya.', 'Manfaatkan safar untuk mendoakan diri dan keluarga; mintalah doa orang tua; dan takutlah doa orang yang Anda zalimi — antara doa itu dan Allah tidak ada penghalang (HR. Bukhari no. 2448).', NULL, 'HR. Tirmidzi no. 1905, Abu Dawud no. 1536 (hasan)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 8, 'Doa untuk Saudara Tanpa Sepengetahuannya', 'دَعْوَةُ الْمَرْءِ الْمُسْلِمِ لِأَخِيهِ بِظَهْرِ الْغَيْبِ مُسْتَجَابَةٌ، عِنْدَ رَأْسِهِ مَلَكٌ مُوَكَّلٌ... قَالَ الْمَلَكُ الْمُوَكَّلُ بِهِ: آمِينَ وَلَكَ بِمِثْلٍ', 'Da''watul-mar''il-muslimi li akhihi bizhahril-ghaibi mustajabah, ''inda ra''sihi malakun muwakkal... qalal-malakul-muwakkalu bihi: amin wa laka bimitsl', 'Doa seorang muslim untuk saudaranya tanpa sepengetahuannya itu mustajab; di dekat kepalanya ada malaikat yang ditugaskan — setiap ia mendoakan kebaikan, malaikat itu berkata: "Amin, dan bagimu yang semisalnya."', 'Ingin doa Anda dikabulkan? Doakan saudara Anda diam-diam dengan doa yang sama.', NULL, 'HR. Muslim no. 2733');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 9, 'Ketika Hujan Turun', 'اُطْلُبُوا اسْتِجَابَةَ الدُّعَاءِ... وَتَحْتَ الْمَطَرِ (اثْنَتَانِ مَا تُرَدَّانِ: الدُّعَاءُ عِنْدَ النِّدَاءِ وَتَحْتَ الْمَطَرِ)', 'Itsnatani ma turaddani: ad-du''a''u ''indan-nida''i wa tahtal-mathar', 'Dua doa yang tidak ditolak: doa ketika adzan dan doa ketika hujan turun.', 'Saat hujan adalah waktu turunnya rahmat. Disunnahkan juga membaca: "Allahumma shayyiban nafi''an" (Ya Allah, jadikanlah hujan yang bermanfaat).', NULL, 'HR. Abu Dawud no. 2540, dinilai sahih oleh al-Hakim');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 10, 'Lailatul Qadar', 'اللَّهُمَّ إِنَّكَ عَفُوٌّ تُحِبُّ الْعَفْوَ فَاعْفُ عَنِّي', 'Allahumma innaka ''afuwwun tuhibbul-''afwa fa''fu ''anni', 'Ya Allah, sesungguhnya Engkau Maha Pemaaf dan mencintai maaf, maka maafkanlah aku.', 'Doa yang Rasulullah ﷺ ajarkan kepada Aisyah untuk malam Lailatul Qadar. Kejar di sepuluh malam terakhir Ramadhan, terutama malam-malam ganjil.', NULL, 'HR. Tirmidzi no. 3513, Ibnu Majah no. 3850 (sahih)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 11, 'Hari Arafah', 'خَيْرُ الدُّعَاءِ دُعَاءُ يَوْمِ عَرَفَةَ، وَخَيْرُ مَا قُلْتُ أَنَا وَالنَّبِيُّونَ مِنْ قَبْلِي: لَا إِلَهَ إِلَّا اللهُ وَحْدَهُ لَا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ', 'Khairud-du''a''i du''a''u yaumi ''Arafah, wa khairu ma qultu ana wan-nabiyyuna min qabli: la ilaha illallahu wahdahu la syarika lah, lahul-mulku wa lahul-hamdu wa huwa ''ala kulli syai''in qadir', 'Sebaik-baik doa adalah doa hari Arafah, dan sebaik-baik yang aku dan para nabi sebelumku ucapkan: tiada tuhan selain Allah semata, tiada sekutu bagi-Nya; milik-Nya kerajaan dan pujian, dan Dia Mahakuasa atas segala sesuatu.', 'Baik yang sedang wukuf maupun yang di rumah: 9 Dzulhijjah adalah hari doa terbaik dalam setahun. Yang tidak berhaji disunnahkan berpuasa.', NULL, 'HR. Tirmidzi no. 3585 (hasan)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 12, 'Doa Dzun-Nun (Saat Terhimpit Kesulitan)', 'لَا إِلَهَ إِلَّا أَنْتَ سُبْحَانَكَ إِنِّي كُنْتُ مِنَ الظَّالِمِينَ', 'La ilaha illa anta subhanaka inni kuntu minazh-zhalimin', 'Tiada tuhan selain Engkau, Mahasuci Engkau; sesungguhnya aku termasuk orang-orang yang zalim.', 'Doa Nabi Yunus dalam perut ikan. Rasulullah ﷺ bersabda: tidaklah seorang muslim berdoa dengannya dalam kesulitan apa pun melainkan Allah mengabulkannya.', NULL, 'QS. Al-Anbiya: 87 · HR. Tirmidzi no. 3505 (sahih)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 13, 'Ketika Terbangun di Tengah Malam', 'مَنْ تَعَارَّ مِنَ اللَّيْلِ فَقَالَ: لَا إِلَهَ إِلَّا اللهُ وَحْدَهُ لَا شَرِيكَ لَهُ... ثُمَّ قَالَ: اللَّهُمَّ اغْفِرْ لِي، أَوْ دَعَا، اسْتُجِيبَ لَهُ', 'Man ta''arra minal-laili faqala: la ilaha illallahu wahdahu la syarika lah... tsumma qala: Allahummaghfir li, au da''a, ustujiba lahu', 'Siapa terbangun di malam hari lalu mengucapkan: "La ilaha illallah wahdahu la syarika lah..." kemudian ia beristighfar atau berdoa, niscaya dikabulkan; dan jika ia berwudhu lalu shalat, diterima shalatnya.', 'Terbangun tengah malam bukan kebetulan — sambut dengan kalimat tauhid lalu doa.', NULL, 'HR. Bukhari no. 1154');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('doa-mustajab', 14, 'Berdoa dengan Asmaul Husna & Keyakinan', 'ادْعُوا اللهَ وَأَنْتُمْ مُوقِنُونَ بِالإِجَابَةِ، وَاعْلَمُوا أَنَّ اللهَ لَا يَسْتَجِيبُ دُعَاءً مِنْ قَلْبٍ غَافِلٍ لَاهٍ', 'Ud''ullaha wa antum muqinuna bil-ijabah, wa''lamu annallaha la yastajibu du''a''an min qalbin ghafilin lah', 'Berdoalah kepada Allah dalam keadaan yakin akan dikabulkan, dan ketahuilah bahwa Allah tidak mengabulkan doa dari hati yang lalai.', 'Adab kunci semua waktu mustajab: hadirkan hati, yakin, awali dengan hamdalah dan shalawat, konsumsi yang halal, dan jangan tergesa berkata "doaku tak kunjung dikabulkan" (HR. Bukhari no. 6340).', NULL, 'HR. Tirmidzi no. 3479 (hasan) · QS. Ghafir: 60');
